FROM jsonb_to_recordset('[{"id": "cap-106-math-001", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "算式(−2) × −5 − −3 之值為何？", "options": ["13", "7", "−13", "−7"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   算式(−2) × −5 − −3 之值為何？\n     (A) 13\n     (B) 7\n     (C) −13\n     (D) −7\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-001", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "今有甲、乙、丙三名候選人參與某村村長選舉，共發出 1800 張選票，得票數\n最高者為當選人，且廢票不計入任何一位候選人之得票數內。全村設有四個\n投開票所，目前第一、第二、第三投開票所已開完所有選票，剩下第四投開\n票所尚未開票，結果如表 ( 一 ) 所示：\n表(一)\n請回答下列問題：\n(1) 請分別寫出目前甲、乙、丙三名候選人的得票數。\n(2) 承 (1)，請分別判斷甲、乙兩名候選人是否還有機會當選村長，並詳細解\n釋或完整寫出你的解題過程。", "options": ["", "", "", ""], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image", "option_incomplete", "option_image"], "parse_confidence": 0.25, "original_question_number": 1, "raw_text": "1.   今有甲、乙、丙三名候選人參與某村村長選舉，共發出 1800 張選票，得票數\n     最高者為當選人，且廢票不計入任何一位候選人之得票數內。全村設有四個\n     投開票所，目前第一、第二、第三投開票所已開完所有選票，剩下第四投開\n     票所尚未開票，結果如表 ( 一 ) 所示：\n\n                          表(一)\n\n\n\n\n     請回答下列問題：\n     (1) 請分別寫出目前甲、乙、丙三名候選人的得票數。\n     (2) 承 (1)，請分別判斷甲、乙兩名候選人是否還有機會當選村長，並詳細解\n       釋或完整寫出你的解題過程。\n\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-002", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "下列哪一個選項中的等式成立？", "options": ["2 =2", "3 =3", "4 =4", "5 =5"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2.   下列哪一個選項中的等式成立？\n     (A)     2 =2\n     (B)     3 =3\n     (C)     4 =4\n     (D)     5 =5\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-002", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "如圖 ( 十五 ) ，在坐標平面上，O 為原點，另有 A ( 0,3 ) 、B ( − 5,0 ) 、C ( 6,0 )\n三點，直線 L 通過 C 點且與 y 軸相交於 D 點。\n請回答下列問題：\n(1) 已知直線 L 的方程式為 5x − 3y = k，求 k 的值。\n(2) 承 (1)，請完整說明 △ AOB 與 △ COD 相似\n的理由。\n圖 ( 十五 )\n參考公式：\n 和的平方公式：( a + b ) 2 = a 2 + 2ab + b 2\n差的平方公式：( a − b ) 2 = a 2 − 2ab + b 2\n平方差公式：a 2 − b 2 = ( a + b )( a − b )\n 若直角三角形兩股長為 a、b，斜邊長為 c ，則 c 2 = a 2 + b 2\n 若圓的半徑為 r，圓周率為 π，則圓面積 = π r 2 ，圓周長 = 2 π r\n 若一個等差數列的首項為 a 1，公差為 d，第 n 項為 a n，前 n 項和為 S n，\nn ( a1 + an)\n則 an = a1 + (n − 1) d，Sn =\n−b ± b2 − 4 a c\n 一元二次方程式 ax + bx + c = 0 的解為 x =\n2a", "options": ["", "", "", ""], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": ["needs_image", "option_incomplete", "option_image"], "parse_confidence": 0.25, "original_question_number": 2, "raw_text": "2.     如圖 ( 十五 ) ，在坐標平面上，O 為原點，另有 A ( 0,3 ) 、B ( − 5,0 ) 、C ( 6,0 )\n       三點，直線 L 通過 C 點且與 y 軸相交於 D 點。\n       請回答下列問題：\n       (1) 已知直線 L 的方程式為 5x − 3y = k，求 k 的值。\n       (2) 承 (1)，請完整說明 △ AOB 與 △ COD 相似\n          的理由。\n\n\n\n\n                                                       圖 ( 十五 )\n\n\n\n\n\n\n參考公式：\n\n      和的平方公式：( a + b ) 2 = a 2 + 2ab + b 2\n        差的平方公式：( a − b ) 2 = a 2 − 2ab + b 2\n        平方差公式：a 2 − b 2 = ( a + b )( a − b )\n      若直角三角形兩股長為 a、b，斜邊長為 c ，則 c 2 = a 2 + b 2\n      若圓的半徑為 r，圓周率為 π，則圓面積 = π r 2 ，圓周長 = 2 π r\n      若一個等差數列的首項為 a 1，公差為 d，第 n 項為 a n，前 n 項和為 S n，\n                        n ( a1 + an)\n       則 an = a1 + (n − 1) d，Sn =\n                                       −b ± b2 − 4 a c\n      一元二次方程式 ax + bx + c = 0 的解為 x =\n                                            2a\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-003", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "計算 6x•(3 − 2x) 的結果，與下列哪一個式子相同？", "options": ["−12x2 + 18x", "−12x2 + 3", "16x", "6x"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3.   計算 6x•(3 − 2x) 的結果，與下列哪一個式子相同？\n     (A) −12x2 + 18x\n     (B) −12x2 + 3\n     (C) 16x\n     (D) 6x\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-004", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "若阿光以四種不同的方式連接正六邊形 ABCDEF 的兩條對角線，連接後的\n情形如下列選項中的圖形所示，則下列哪一個圖形不是線對稱圖形？", "options": ["", "", "", ""], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 4, "raw_text": "4.   若阿光以四種不同的方式連接正六邊形 ABCDEF 的兩條對角線，連接後的\n     情形如下列選項中的圖形所示，則下列哪一個圖形不是線對稱圖形？\n     (A)\t\t\t(B)                    (C)    (D)\n\n\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-005", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "已 知 坐 標 平 面 上 有 兩 直 線 相 交 於 一 點 ( 2,a ) ， 且 兩 直 線 的 方 程 式 分 別 為\n2x + 3y = 7、 3x − 2y = b，其中 a、 b 為兩數。求 a + b 之值為何？", "options": ["1", "−1", "5", "−5"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5.   已 知 坐 標 平 面 上 有 兩 直 線 相 交 於 一 點 ( 2,a ) ， 且 兩 直 線 的 方 程 式 分 別 為\n     2x + 3y = 7、 3x − 2y = b，其中 a、 b 為兩數。求 a + b 之值為何？\n     (A) 1\n     (B) −1\n     (C) 5\n     (D) −5\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-006", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "阿信、小怡兩人打算搭乘同一班次電車上學。若此班次電車共有 5 節車廂，且\n阿信從任意一節車廂上車的機會相等，小怡從任意一節車廂上車的機會相等，\n則兩人從同一節車廂上車的機率為何？", "options": ["", "", "", ""], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": ["option_incomplete", "option_image"], "parse_confidence": 0.4, "original_question_number": 6, "raw_text": "6.   阿信、小怡兩人打算搭乘同一班次電車上學。若此班次電車共有 5 節車廂，且\n     阿信從任意一節車廂上車的機會相等，小怡從任意一節車廂上車的機會相等，\n     則兩人從同一節車廂上車的機率為何？\n     (A)\n     (B)\n     (C)\n     (D)\n\n\n"}, "is_active": false, "auto_gradable": false, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-007", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "平面上有 A、B、C 三點，其中 AB = 3，BC = 4，AC = 5。若分別以 A、B、C\n為圓心，半徑長為 2 畫圓，畫出圓 A、圓 B、圓 C，則下列敘述何者正確？", "options": ["圓 A 與圓 C 外切，圓 B 與圓 C 外切", "圓 A 與圓 C 外切，圓 B 與圓 C 外離", "圓 A 與圓 C 外離，圓 B 與圓 C 外切", "圓 A 與圓 C 外離，圓 B 與圓 C 外離"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T19:26:38+00:00", "source_pdf_sha1": "b378ee559c35", "answer_pdf_sha1": "0fa526cf1539", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7.   平面上有 A、B、C 三點，其中 AB = 3，BC = 4，AC = 5。若分別以 A、B、C\n     為圓心，半徑長為 2 畫圓，畫出圓 A、圓 B、圓 C，則下列敘述何者正確？\n     (A) 圓 A 與圓 C 外切，圓 B 與圓 C 外切\n     (B) 圓 A 與圓 C 外切，圓 B 與圓 C 外離\n     (C) 圓 A 與圓 C 外離，圓 B 與圓 C 外切\n     (D) 圓 A 與圓 C 外離，圓 B 與圓 C 外離\n\n\n\n"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": null}, {"id": "cap-106-math-008", "exam_id": "cap", "subject_id": "sub-cap-math", "paper_id": "cap-106-math", "question_type": "single_choice", "question_text": "下列選項中所表示的數，哪一個與 252 的最大公因數為 42 ？", "options": ["2 × 3 × 52 × 72", "2 × 32 × 5 × 72", "22 × 3 × 52 × 7", "22 × 32 × 5 × 7"], "correct_answer": 0, "correct_ans